// Input validation helpers for API endpoints.
//
// Each validator returns an array of error message strings. An empty array
// means the value passed validation. The `validate` helper runs a set of
// field validators against a payload and returns a combined list of errors
// suitable for a 400 response body.

// RFC 5321 caps the full address at 254 characters. The regex below is a
// pragmatic "looks like an email" check — not a full RFC 5322 parser, but
// sufficient for rejecting obviously malformed input at the API boundary.
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const EMAIL_MAX_LENGTH = 254;
const NAME_MIN_LENGTH = 1;
const NAME_MAX_LENGTH = 100;

function isPresent(value) {
  return value !== undefined && value !== null && value !== '';
}

function validateRequired(field, value) {
  if (!isPresent(value)) {
    return [`${field} is required`];
  }
  return [];
}

function validateId(field, value) {
  const errors = validateRequired(field, value);
  if (errors.length > 0) return errors;

  // Accept numeric strings (e.g. from route params) and numbers. Reject
  // anything else, plus non-finite / non-integer / negative values.
  const asNumber = typeof value === 'number' ? value : Number(value);
  if (!Number.isFinite(asNumber) || !Number.isInteger(asNumber) || asNumber < 0) {
    return [`${field} must be a non-negative integer`];
  }
  return [];
}

function validateName(field, value) {
  const errors = validateRequired(field, value);
  if (errors.length > 0) return errors;

  const fieldErrors = [];
  if (typeof value !== 'string') {
    fieldErrors.push(`${field} must be a string`);
    return fieldErrors;
  }
  if (value.length < NAME_MIN_LENGTH || value.length > NAME_MAX_LENGTH) {
    fieldErrors.push(
      `${field} must be between ${NAME_MIN_LENGTH} and ${NAME_MAX_LENGTH} characters`
    );
  }
  return fieldErrors;
}

function validateEmail(field, value) {
  const errors = validateRequired(field, value);
  if (errors.length > 0) return errors;

  const fieldErrors = [];
  if (typeof value !== 'string') {
    fieldErrors.push(`${field} must be a string`);
    return fieldErrors;
  }
  if (value.length > EMAIL_MAX_LENGTH) {
    fieldErrors.push(`${field} must be at most ${EMAIL_MAX_LENGTH} characters`);
  }
  if (!EMAIL_REGEX.test(value)) {
    fieldErrors.push(`${field} must be a valid email address`);
  }
  return fieldErrors;
}

// Runs an object of `{ fieldName: validatorFn }` against `payload` and
// returns a flat array of error strings. Each validator receives
// `(fieldName, value)` and returns an array of error messages.
function validate(payload, validators) {
  const source = payload || {};
  const errors = [];
  for (const [field, validator] of Object.entries(validators)) {
    errors.push(...validator(field, source[field]));
  }
  return errors;
}

// Express middleware factory: runs `validate` against `req[source]` and
// responds 400 with `{ error, details }` if any validation fails.
function validationMiddleware(source, validators) {
  return (req, res, next) => {
    const errors = validate(req[source], validators);
    if (errors.length > 0) {
      return res.status(400).json({
        error: 'Validation failed',
        details: errors,
      });
    }
    return next();
  };
}

module.exports = {
  validate,
  validationMiddleware,
  validateRequired,
  validateId,
  validateName,
  validateEmail,
  EMAIL_MAX_LENGTH,
  NAME_MIN_LENGTH,
  NAME_MAX_LENGTH,
};

