// Validation helper module
// Provides reusable validators and a validation runner for route handlers.

// RFC 5321 practical max for an email address.
const EMAIL_MAX_LENGTH = 254;
const NAME_MIN_LENGTH = 1;
const NAME_MAX_LENGTH = 100;

// Reasonably strict email regex: single "@", non-empty local/domain parts,
// at least one "." in the domain, no spaces.
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Check that a value is "present" (not undefined, null, or empty string).
 */
function isPresent(value) {
  return value !== undefined && value !== null && value !== '';
}

/**
 * Validate that `value` is a numeric id.
 * Accepts either a number or a numeric string; must be a finite integer >= 1.
 */
function validateId(value, fieldName = 'id') {
  const errors = [];

  if (!isPresent(value)) {
    errors.push(`${fieldName} is required`);
    return errors;
  }

  let num;
  if (typeof value === 'number') {
    num = value;
  } else if (typeof value === 'string' && /^-?\d+$/.test(value.trim())) {
    num = Number(value);
  } else {
    errors.push(`${fieldName} must be numeric`);
    return errors;
  }

  if (!Number.isFinite(num) || !Number.isInteger(num)) {
    errors.push(`${fieldName} must be an integer`);
  } else if (num < 1) {
    errors.push(`${fieldName} must be a positive integer`);
  }

  return errors;
}

/**
 * Validate a name: must be a string of length 1-100.
 */
function validateName(value, fieldName = 'name') {
  const errors = [];

  if (!isPresent(value)) {
    errors.push(`${fieldName} is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`${fieldName} must be a string`);
    return errors;
  }

  if (value.length < NAME_MIN_LENGTH || value.length > NAME_MAX_LENGTH) {
    errors.push(
      `${fieldName} must be between ${NAME_MIN_LENGTH} and ${NAME_MAX_LENGTH} characters`
    );
  }

  return errors;
}

/**
 * Validate an email: must be a string, match the email format, and be <= 254 chars.
 */
function validateEmail(value, fieldName = 'email') {
  const errors = [];

  if (!isPresent(value)) {
    errors.push(`${fieldName} is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`${fieldName} must be a string`);
    return errors;
  }

  if (value.length > EMAIL_MAX_LENGTH) {
    errors.push(`${fieldName} must be at most ${EMAIL_MAX_LENGTH} characters`);
  }

  if (!EMAIL_REGEX.test(value)) {
    errors.push(`${fieldName} must be a valid email address`);
  }

  return errors;
}

/**
 * Run a set of validators and return a combined error list.
 *
 * @param {Array<{fn: Function, value: any, field: string}>} checks
 * @returns {string[]} flat array of error messages (empty if all passed)
 */
function runValidators(checks) {
  const errors = [];
  for (const { fn, value, field } of checks) {
    errors.push(...fn(value, field));
  }
  return errors;
}

/**
 * Express helper: if `errors` is non-empty, send a 400 response describing
 * every validation that failed, and return true. Otherwise return false.
 */
function sendValidationError(res, errors) {
  if (errors && errors.length > 0) {
    res.status(400).json({
      error: 'Validation failed',
      details: errors,
    });
    return true;
  }
  return false;
}

module.exports = {
  // constants
  EMAIL_MAX_LENGTH,
  NAME_MIN_LENGTH,
  NAME_MAX_LENGTH,
  // individual validators
  validateId,
  validateName,
  validateEmail,
  // helpers
  isPresent,
  runValidators,
  sendValidationError,
};

