// validation.js
// Reusable input-validation helpers for API route handlers.
//
// Each validator function returns either `null` (valid) or a string error
// message describing why the value is invalid. The top-level `validate`
// function runs a schema of validators against a payload and returns a list
// of error messages, which route handlers can surface as a 400 response.

'use strict';

// RFC-5321 caps the full address at 254 characters. The regex is intentionally
// pragmatic rather than RFC-perfect: one "@", at least one char on each side,
// and a dot in the domain portion.
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const EMAIL_MAX_LEN = 254;
const NAME_MIN_LEN = 1;
const NAME_MAX_LEN = 100;

function isPresent(value) {
  return value !== undefined && value !== null && value !== '';
}

// ---------- Field validators ----------

function validateId(value, { fieldName = 'id' } = {}) {
  if (!isPresent(value)) return `${fieldName} is required`;
  // Accept numeric strings (e.g. route params) as well as numbers.
  const n = typeof value === 'number' ? value : Number(value);
  if (!Number.isFinite(n)) return `${fieldName} must be numeric`;
  if (!Number.isInteger(n) || n <= 0) {
    return `${fieldName} must be a positive integer`;
  }
  return null;
}

function validateName(value, { fieldName = 'name' } = {}) {
  if (!isPresent(value)) return `${fieldName} is required`;
  if (typeof value !== 'string') return `${fieldName} must be a string`;
  if (value.length < NAME_MIN_LEN || value.length > NAME_MAX_LEN) {
    return `${fieldName} must be between ${NAME_MIN_LEN} and ${NAME_MAX_LEN} characters`;
  }
  return null;
}

function validateEmail(value, { fieldName = 'email' } = {}) {
  if (!isPresent(value)) return `${fieldName} is required`;
  if (typeof value !== 'string') return `${fieldName} must be a string`;
  if (value.length > EMAIL_MAX_LEN) {
    return `${fieldName} must be at most ${EMAIL_MAX_LEN} characters`;
  }
  if (!EMAIL_REGEX.test(value)) {
    return `${fieldName} must be a valid email address`;
  }
  return null;
}

// ---------- Schema runner ----------

// Given a payload object and a schema like:
//   { id: { validator: validateId }, name: { validator: validateName } }
// return an array of error strings (empty array means valid).
function runSchema(payload, schema) {
  const errors = [];
  const source = payload || {};
  for (const [field, spec] of Object.entries(schema)) {
    const err = spec.validator(source[field], { fieldName: field });
    if (err) errors.push(err);
  }
  return errors;
}

// Express middleware factory. Validates `req[source]` against the schema and
// short-circuits with a 400 listing every failed check when any errors occur.
function validateRequest(schema, source = 'body') {
  return function validateRequestMiddleware(req, res, next) {
    const errors = runSchema(req[source], schema);
    if (errors.length > 0) {
      return res.status(400).json({
        error: 'Validation failed',
        details: errors,
      });
    }
    return next();
  };
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  runSchema,
  validateRequest,
  // Exported for tests / reuse
  EMAIL_REGEX,
  EMAIL_MAX_LEN,
  NAME_MIN_LEN,
  NAME_MAX_LEN,
};

