// Input validation helpers for API endpoints.
//
// Each validator returns an array of human-readable error strings.
// An empty array means the input passed validation.
//
// The `validate(...)` helper composes multiple field checks and returns a
// single { valid, errors } result suitable for turning into a 400 response.

// RFC 5321 caps the full address at 254 octets. We combine that with a
// reasonably strict (but not pathological) syntactic check.
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const EMAIL_MAX_LENGTH = 254;
const NAME_MIN_LENGTH = 1;
const NAME_MAX_LENGTH = 100;

function isPresent(value) {
  return value !== undefined && value !== null && value !== '';
}

// id may arrive as a route param (string) or a JSON number; both are accepted
// as long as the result is a finite, non-negative integer.
function validateId(value, fieldName = 'id') {
  const errors = [];
  if (!isPresent(value)) {
    errors.push(`${fieldName} is required`);
    return errors;
  }
  const asNumber = typeof value === 'number' ? value : Number(value);
  if (!Number.isFinite(asNumber)) {
    errors.push(`${fieldName} must be numeric`);
    return errors;
  }
  if (!Number.isInteger(asNumber) || asNumber < 0) {
    errors.push(`${fieldName} must be a non-negative integer`);
  }
  return errors;
}

function validateName(value, fieldName = 'name') {
  const errors = [];
  if (!isPresent(value)) {
    errors.push(`${fieldName} is required`);
    return errors;
  }
  if (typeof value !== 'string') {
    errors.push(`${fieldName} must be a string`);
    return errors;
  }
  if (value.length < NAME_MIN_LENGTH || value.length > NAME_MAX_LENGTH) {
    errors.push(
      `${fieldName} must be between ${NAME_MIN_LENGTH} and ${NAME_MAX_LENGTH} characters`
    );
  }
  return errors;
}

function validateEmail(value, fieldName = 'email') {
  const errors = [];
  if (!isPresent(value)) {
    errors.push(`${fieldName} is required`);
    return errors;
  }
  if (typeof value !== 'string') {
    errors.push(`${fieldName} must be a string`);
    return errors;
  }
  if (value.length > EMAIL_MAX_LENGTH) {
    errors.push(`${fieldName} must be at most ${EMAIL_MAX_LENGTH} characters`);
  }
  if (!EMAIL_REGEX.test(value)) {
    errors.push(`${fieldName} must be a valid email address`);
  }
  return errors;
}

// Field-level validator registry. Lets callers declare which fields to check
// without manually stitching together the per-field helpers.
const VALIDATORS = {
  id: validateId,
  name: validateName,
  email: validateEmail,
};

/**
 * Run a set of field validators against an input object.
 *
 * @param {object} input - object containing the fields to validate.
 * @param {string[]} fields - which fields to validate (keys of VALIDATORS).
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validate(input, fields) {
  const errors = [];
  if (input === null || typeof input !== 'object') {
    return { valid: false, errors: ['request body must be a JSON object'] };
  }
  for (const field of fields) {
    const validator = VALIDATORS[field];
    if (!validator) {
      throw new Error(`Unknown validator: ${field}`);
    }
    errors.push(...validator(input[field], field));
  }
  return { valid: errors.length === 0, errors };
}

/**
 * Express middleware factory. Validates the request body against the given
 * fields and short-circuits with a 400 response if anything fails.
 */
function validateBody(fields) {
  return (req, res, next) => {
    const result = validate(req.body || {}, fields);
    if (!result.valid) {
      return res.status(400).json({
        error: 'Validation failed',
        details: result.errors,
      });
    }
    next();
  };
}

/**
 * Express middleware factory for validating route params (e.g. /users/:id).
 */
function validateParams(fields) {
  return (req, res, next) => {
    const result = validate(req.params || {}, fields);
    if (!result.valid) {
      return res.status(400).json({
        error: 'Validation failed',
        details: result.errors,
      });
    }
    next();
  };
}

module.exports = {
  validate,
  validateBody,
  validateParams,
  validateId,
  validateName,
  validateEmail,
  // exported for tests / callers that want to tweak limits
  constants: {
    EMAIL_MAX_LENGTH,
    NAME_MIN_LENGTH,
    NAME_MAX_LENGTH,
  },
};

