// Input validation helpers.
//
// Each validator returns either `null` when the value is valid, or a string
// describing what went wrong. Higher-level helpers collect those strings and
// produce a structured 400 response so route handlers stay small.

// RFC 5321 caps the full address at 254 characters. The regex is deliberately
// pragmatic rather than fully RFC 5322 compliant — it rejects obviously bad
// input without pulling in a dependency.
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const EMAIL_MAX_LENGTH = 254;
const NAME_MIN_LENGTH = 1;
const NAME_MAX_LENGTH = 100;

function validateId(value) {
  if (value === undefined || value === null || value === '') {
    return 'id is required';
  }
  // Accept numeric strings (from path/query params) as well as real numbers.
  const asNumber = typeof value === 'number' ? value : Number(value);
  if (!Number.isFinite(asNumber)) {
    return 'id must be numeric';
  }
  if (!Number.isInteger(asNumber)) {
    return 'id must be an integer';
  }
  if (asNumber <= 0) {
    return 'id must be a positive integer';
  }
  return null;
}

function validateName(value) {
  if (value === undefined || value === null) {
    return 'name is required';
  }
  if (typeof value !== 'string') {
    return 'name must be a string';
  }
  if (value.length < NAME_MIN_LENGTH) {
    return `name must be at least ${NAME_MIN_LENGTH} character(s)`;
  }
  if (value.length > NAME_MAX_LENGTH) {
    return `name must be at most ${NAME_MAX_LENGTH} characters`;
  }
  return null;
}

function validateEmail(value) {
  if (value === undefined || value === null || value === '') {
    return 'email is required';
  }
  if (typeof value !== 'string') {
    return 'email must be a string';
  }
  if (value.length > EMAIL_MAX_LENGTH) {
    return `email must be at most ${EMAIL_MAX_LENGTH} characters`;
  }
  if (!EMAIL_REGEX.test(value)) {
    return 'email must be a valid email address';
  }
  return null;
}

// Spec: { fieldName: validatorFn }. Runs every validator and collects errors.
function validate(values, spec) {
  const errors = [];
  for (const [field, validator] of Object.entries(spec)) {
    const err = validator(values[field]);
    if (err) errors.push(err);
  }
  return errors;
}

// Express middleware factory: validates req against the supplied spec and
// short-circuits with a 400 listing every failed rule.
//
//   sources: which parts of the request to merge for validation, in order
//            (later keys override earlier ones). Defaults to body only.
function validateRequest(spec, sources = ['body']) {
  return (req, res, next) => {
    const values = {};
    for (const source of sources) {
      Object.assign(values, req[source] || {});
    }
    const errors = validate(values, spec);
    if (errors.length > 0) {
      return res.status(400).json({
        error: 'Validation failed',
        details: errors,
      });
    }
    next();
  };
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validate,
  validateRequest,
  EMAIL_MAX_LENGTH,
  NAME_MIN_LENGTH,
  NAME_MAX_LENGTH,
};

