// validation.js
// Reusable input validation helpers for API route handlers.
//
// Each validator returns either `null` (valid) or a string describing the
// failure. The top-level `validate(schema, data)` function runs a set of
// per-field rules and returns an array of error messages. `validationMiddleware`
// wraps that in an Express middleware that responds with a descriptive 400.

'use strict';

// RFC 5321 practical upper bound on email addresses.
const EMAIL_MAX_LENGTH = 254;
const NAME_MIN_LENGTH = 1;
const NAME_MAX_LENGTH = 100;

// Pragmatic email regex: one "@", non-empty local part, a dot in the domain,
// and no whitespace. Good enough for request-level validation; deeper checks
// belong in a dedicated library if ever needed.
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Asserts a value is present (not undefined, null, or empty string).
 * @param {string} field
 * @param {unknown} value
 * @returns {string|null}
 */
function required(field, value) {
  if (value === undefined || value === null || value === '') {
    return `${field} is required`;
  }
  return null;
}

/**
 * Asserts a value is a finite numeric id (integer > 0). Accepts numbers or
 * numeric strings (common for path/query params).
 * @param {string} field
 * @param {unknown} value
 * @returns {string|null}
 */
function isNumericId(field, value) {
  if (value === undefined || value === null || value === '') return null; // let `required` own presence
  let n;
  if (typeof value === 'number') {
    n = value;
  } else if (typeof value === 'string' && value.trim() !== '' && /^-?\d+$/.test(value.trim())) {
    n = Number(value);
  } else {
    return `${field} must be a numeric id`;
  }
  if (!Number.isFinite(n) || !Number.isInteger(n) || n <= 0) {
    return `${field} must be a positive integer`;
  }
  return null;
}

/**
 * Asserts a value is a string within [min, max] length (inclusive).
 * @param {string} field
 * @param {unknown} value
 * @param {{min?: number, max?: number}} [opts]
 * @returns {string|null}
 */
function isString(field, value, opts = {}) {
  if (value === undefined || value === null || value === '') return null;
  if (typeof value !== 'string') {
    return `${field} must be a string`;
  }
  const { min, max } = opts;
  if (typeof min === 'number' && value.length < min) {
    return `${field} must be at least ${min} character${min === 1 ? '' : 's'}`;
  }
  if (typeof max === 'number' && value.length > max) {
    return `${field} must be at most ${max} character${max === 1 ? '' : 's'}`;
  }
  return null;
}

/**
 * Asserts a value looks like an email and is within length limits.
 * @param {string} field
 * @param {unknown} value
 * @returns {string|null}
 */
function isEmail(field, value) {
  if (value === undefined || value === null || value === '') return null;
  if (typeof value !== 'string') {
    return `${field} must be a string`;
  }
  if (value.length > EMAIL_MAX_LENGTH) {
    return `${field} must be at most ${EMAIL_MAX_LENGTH} characters`;
  }
  if (!EMAIL_REGEX.test(value)) {
    return `${field} must be a valid email address`;
  }
  return null;
}

/**
 * A schema is an object of `{ fieldName: [ruleFn, ...] }` where each rule is
 * `(field, value) => string|null`. Returns an array of error strings (empty
 * when valid).
 *
 * @param {Record<string, Array<(field: string, value: unknown) => string|null>>} schema
 * @param {Record<string, unknown>} data
 * @returns {string[]}
 */
function validate(schema, data) {
  const errors = [];
  const source = data || {};
  for (const field of Object.keys(schema)) {
    const rules = schema[field];
    const value = source[field];
    for (const rule of rules) {
      const err = rule(field, value);
      if (err) {
        errors.push(err);
        break; // one error per field is plenty; avoids duplicate "required"+"type" noise
      }
    }
  }
  return errors;
}

/**
 * Convenience builders so route files read declaratively.
 */
const rules = {
  required: () => (field, value) => required(field, value),
  numericId: () => (field, value) => isNumericId(field, value),
  string: (opts) => (field, value) => isString(field, value, opts),
  email: () => (field, value) => isEmail(field, value),
};

/**
 * Express middleware factory. Pulls fields from the chosen source (`body`,
 * `params`, or `query`), runs the schema, and responds with a 400 listing
 * every failure when any rule fails.
 *
 * @param {Record<string, Array<(field: string, value: unknown) => string|null>>} schema
 * @param {'body'|'params'|'query'} [source='body']
 */
function validationMiddleware(schema, source = 'body') {
  return function (req, res, next) {
    const data = req[source];
    const errors = validate(schema, data);
    if (errors.length > 0) {
      return res.status(400).json({
        error: 'Validation failed',
        details: errors,
      });
    }
    return next();
  };
}

module.exports = {
  required,
  isNumericId,
  isString,
  isEmail,
  validate,
  validationMiddleware,
  rules,
  EMAIL_MAX_LENGTH,
  NAME_MIN_LENGTH,
  NAME_MAX_LENGTH,
};
